def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        penalty = 1.0
        reward = 0.0
        base_multiplier = 1.0
        for j in range(1, 15):
            if j % 3 == 0:
                base_multiplier *= 1.05
            if j % 4 == 1:
                base_multiplier *= 0.95
            if ratio < 0.1 * j:
                score += (j ** 2) * np.exp(-0.5 * ratio * j) * base_multiplier
            else:
                score += (np.log1p(j * 2) + ratio ** 1.8) * base_multiplier / (j + 2)
            if cap % (j + 2) == 0:
                score *= 1.04
            elif (cap + j * 2) % 5 == 0:
                score *= 0.96
            if j % 5 == 0:
                for k in range(1, 7):
                    diff = cap - item * k * 0.9
                    if diff > 0:
                        if diff % (k + 1) == 0:
                            reward += np.log1p(diff) / (k + 3)
                        else:
                            reward -= np.sqrt(abs(diff)) / (k + 2)
                    else:
                        penalty += (abs(diff) ** 1.3) / (k + 1)
            if j == 12:
                for x in range(1, 4):
                    for y in range(1, 4):
                        val = (cap + j * x) % (y + 2)
                        if val == 0:
                            score *= 1.015
                        elif val < 3:
                            score *= 0.985
        if score == 0:
            priorities[i] = np.inf
        else:
            adj_score = (score + reward) / penalty
            if adj_score < 0:
                priorities[i] = -adj_score * np.log1p(cap * item + 1)
            else:
                if cap > item * 7:
                    priorities[i] = -adj_score / (np.sqrt(cap) + 2)
                elif cap > item * 3:
                    priorities[i] = -adj_score / (cap / 2 + 1)
                else:
                    priorities[i] = -adj_score / (cap + 3)
            if ratio > 0.85:
                priorities[i] *= 1.3
            elif ratio < 0.05:
                priorities[i] *= 0.75
            else:
                priorities[i] *= (1 + 0.1 * np.sin(ratio * 10))
    return priorities
